print(book.average("Ada"))"},{"conversion_notes":"Converted dependency ordering from Python into a Jac graph-processing ability. The Jac version computes indegrees and walks ready nodes with a queue, preserving the topological-order behavior.","jac_code":"can topo_order(graph: dict[str, list[str]]) -> list[str] {
    indegree = {};
    for node in graph {
        indegree[node] = 0;
    }
    for node in graph {
        for next in graph[node] {
            if next in indegree {
                indegree[next] += 1;
            } else {
                indegree[next] = 1;
            }
        }
    }
    ready = [];
    for node in indegree {
        if indegree[node] == 0 {
            ready.append(node);
        }
    }
    order = [];
    index = 0;
    while index < len(ready) {
        node = ready[index];
        index += 1;
        order.append(node);
        if node in graph {
            for next in graph[node] {
                indegree[next] -= 1;
                if indegree[next] == 0 {
                    ready.append(next);
                }
            }
        }
    }
    return order;
}

with entry {
    graph = {"shop": ["cook"], "cook": ["eat"], "eat": [], "set": ["eat"]};
    print(topo_order(graph));
}","python_code":"def topo_order(graph):
    indegree = {}
    for node in graph:
        indegree[node] = 0
    for node in graph:
        for nxt in graph[node]:
            indegree[nxt] = indegree.get(nxt, 0) + 1
    ready = [node for node in indegree if indegree[node] == 0]
    order = []
    index = 0
    while index < len(ready):
        node = ready[index]
        index += 1
        order.append(node)
        for nxt in graph.get(node, []):
            indegree[nxt] -= 1
            if indegree[nxt] == 0:
                ready.append(nxt)
    return order

